/**
 * ADMIN PAGES - Previously Untested
 */
test.describe('Admin Pages - Previously Untested', () => {
  const ADMIN_PAGES = [
    { path: '/admin/ai-analysis.html', name: 'AI Analysis', keywords: ['ai', 'analysis', 'insight'] },
    { path: '/admin/api-builder.html', name: 'API Builder', keywords: ['api', 'builder', 'endpoint'] },
    { path: '/admin/approvals.html', name: 'Approvals', keywords: ['approval', 'pending', 'review'] },
    { path: '/admin/binh-phap.html', name: 'Binh Phap', keywords: ['binh phap', 'strategy', 'tactic'] },
    { path: '/admin/community.html', name: 'Community', keywords: ['community', 'member', 'social'] },
    { path: '/admin/content-calendar.html', name: 'Content Calendar', keywords: ['calendar', 'content', 'schedule'] },
    { path: '/admin/customer-success.html', name: 'Customer Success', keywords: ['customer', 'success', 'support'] },
    { path: '/admin/deploy.html', name: 'Deploy', keywords: ['deploy', 'release', 'build'] },
    { path: '/admin/docs.html', name: 'Docs', keywords: ['docs', 'documentation', 'guide'] },
    { path: '/admin/ecommerce.html', name: 'Ecommerce', keywords: ['ecommerce', 'shop', 'product'] },
    { path: '/admin/events.html', name: 'Events', keywords: ['event', 'activity', 'campaign'] },
    { path: '/admin/index.html', name: 'Admin Index', keywords: ['admin', 'dashboard'] },
    { path: '/admin/landing-builder.html', name: 'Landing Builder', keywords: ['landing', 'builder', 'page'] },
    { path: '/admin/leads.html', name: 'Leads', keywords: ['lead', 'prospect', 'contact'] },
    { path: '/admin/legal.html', name: 'Legal', keywords: ['legal', 'compliance', 'policy'] },
    { path: '/admin/mvp-launch.html', name: 'MVP Launch', keywords: ['mvp', 'launch', 'release'] },
    { path: '/admin/onboarding.html', name: 'Admin Onboarding', keywords: ['onboarding', 'setup', 'guide'] },
    { path: '/admin/payments.html', name: 'Admin Payments', keywords: ['payment', 'transaction', 'billing'] },
    { path: '/admin/pipeline.html', name: 'Pipeline', keywords: ['pipeline', 'sales', 'deal'] },
    { path: '/admin/retention.html', name: 'Retention', keywords: ['retention', 'churn', 'loyalty'] },
    { path: '/admin/roiaas-admin.html', name: 'ROIaaS Admin', keywords: ['roiaas', 'roi', 'analytics'] },
    { path: '/admin/workflows.html', name: 'Workflows', keywords: ['workflow', 'automation', 'flow'] },
  ];

  for (const page of ADMIN_PAGES) {
    test.describe(`${page.name}`, () => {
      test('loads without critical errors', async ({ page: p }) => {
        const errors: string[] = [];

        p.on('pageerror', (error) => {
          // Ignore expected errors
          if (error.message.includes('supabase') || error.message.includes('__ENV__')) return;
          if (/is not defined/.test(error.message) && /createDemo|Auth|mekongAgents/.test(error.message)) return;
          if (error.message.includes('CustomElementRegistry')) return;
          if (error.message.includes('hover') || error.message.includes('touch')) return;
          errors.push(error.message);
        });

        const response = await p.goto(page.path, { waitUntil: 'commit', timeout: 30000 });
        expect(response?.status()).toBe(200);
        // Allow up to 3 non-critical errors
        expect(errors.length).toBeLessThanOrEqual(3);
      });

      test('has valid HTML structure', async ({ page: p }) => {
        await p.goto(page.path, { waitUntil: 'commit', timeout: 30000 });

        // Check DOCTYPE
        const hasDoctype = await p.evaluate(() => document.firstChild?.nodeType === 10);
        expect(hasDoctype).toBe(true);

        // Check html lang
        const htmlLang = await p.getAttribute('html', 'lang');
        expect(htmlLang).toBeTruthy();

        // Check title
        const title = await p.title();
        expect(title.length).toBeGreaterThan(0);
      });

      test('has required meta tags', async ({ page: p }) => {
        await p.goto(page.path, { waitUntil: 'commit', timeout: 30000 });

        // Viewport
        const viewport = await p.getAttribute('meta[name="viewport"]', 'content');
        expect(viewport).toBeTruthy();

        // Charset
        const charset = await p.querySelector('meta[charset]');
        expect(charset).toBeTruthy();
      });

      test('has main content area', async ({ page: p }) => {
        await p.goto(page.path, { waitUntil: 'domcontentloaded', timeout: 30000 });

        // Check for main content
        const hasMain = await p.locator('main, [role="main"], .main-content, .content').count();
        expect(hasMain).toBeGreaterThan(0);
      });
    });
  }
});

