/**
 * ACCESSIBILITY TESTS - Previously Untested Pages
 */
test.describe('Accessibility Tests - Previously Untested', () => {
  const KEY_PAGES = [
    '/admin/ai-analysis.html',
    '/admin/api-builder.html',
    '/admin/content-calendar.html',
    '/admin/deploy.html',
    '/admin/ecommerce.html',
    '/admin/pipeline.html',
    '/admin/workflows.html',
  ];

  for (const pagePath of KEY_PAGES) {
    test(`${pagePath} has accessible landmarks`, async ({ page }) => {
      await page.goto(pagePath, { waitUntil: 'domcontentloaded', timeout: 10000 });

      // Check for main landmark
      const hasMain = await page.locator('[role="main"], main').count();
      expect(hasMain).toBeGreaterThan(0);

      // Check for lang attribute
      const lang = await page.getAttribute('html', 'lang');
      expect(lang).toBeTruthy();
    });

    test(`${pagePath} has proper heading hierarchy`, async ({ page }) => {
      await page.goto(pagePath, { waitUntil: 'domcontentloaded', timeout: 10000 });

      // Check h1 count (should be 0 or 1)
      const h1Count = await page.locator('h1').count();
      expect(h1Count).toBeLessThanOrEqual(1);
    });
  }
});

/**
 * RESPONSIVE TESTS - Mobile Viewports
 */
test.describe('Responsive Tests - Previously Untested Pages', () => {
  const VIEWPORTS = [
    { name: 'Mobile (375px)', width: 375, height: 667 },
    { name: 'Tablet (768px)', width: 768, height: 1024 },
    { name: 'Desktop (1024px)', width: 1024, height: 768 },
  ];

  const TEST_PAGES = [
    '/admin/ai-analysis.html',
    '/admin/content-calendar.html',
    '/admin/ecommerce.html',
    '/admin/pipeline.html',
  ];

  for (const pagePath of TEST_PAGES) {
    for (const viewport of VIEWPORTS) {
      test(`${pagePath} renders on ${viewport.name}`, async ({ page }) => {
        await page.setViewportSize({ width: viewport.width, height: viewport.height });
        await page.goto(pagePath, { waitUntil: 'domcontentloaded', timeout: 10000 });

        // Check page loads
        const content = await page.content();
        expect(content.length).toBeGreaterThan(100);
      });
    }
  }
});

/**
 * PERFORMANCE TESTS - Load Time
 */
test.describe('Performance Tests - Load Time', () => {
  const PAGES = [
    '/admin/ai-analysis.html',
    '/admin/api-builder.html',
    '/admin/content-calendar.html',
    '/admin/ecommerce.html',
    '/admin/pipeline.html',
  ];

  for (const pagePath of PAGES) {
    test(`${pagePath} loads within 3 seconds`, async ({ page }) => {
      const startTime = Date.now();
      const response = await page.goto(pagePath, { waitUntil: 'domcontentloaded', timeout: 10000 });
      const loadTime = Date.now() - startTime;

      expect(response?.status()).toBe(200);
      expect(loadTime).toBeLessThan(3000); // 3 second threshold
    });
  }
});
